import React, { useEffect } from "react";
import ReactDOM from "react-dom";
import { CSSTransition } from "react-transition-group";
import "./EditPropertyModal.css";

const initialFormData = Object.freeze({
    title: "",
    category: "",
    shortDescription: "",
    fullDescription: "",
    city: "",
    state: "",
    country: "",
    hostMessage: "",
    nightlyFee: 0,
    cleaningFee: 0,
    serviceFee: 0,
    guests: 0,
    beds: 0,
    baths: 0,
    amenities: [],
    houseRules: [],
    healthAndSafety: [],
    cancellationPolicy: [],
});

const MODAL_STYLES = {
    position: "absolute",
    backgroundColor: "#FFF",
    padding: "15px",
    zIndex: "1000",
    width: "35%",
    borderRadius: ".5em"
  };

  const OVERLAY_STYLE = {
    position: "fixed",
    display: "flex",
    justifyContent: "center",
    top: "0",
    left: "0",
    width: "100%",
    height: "100%",
    backgroundColor: "rgba(0,0,0, .8)",
    zIndex: "1000",
    overflowY: "auto"
  };


const EditPropertyModal = (props) => {
    console.log(props.data)
    const [formData, updateFormData] = React.useState(initialFormData);
    const closeOnEscapeKeyDown = (e) => {
        if ((e.charCode || e.keyCode) === 27) {
            props.onClose();
        }
    };

    useEffect(() => {
        document.body.addEventListener("keydown", closeOnEscapeKeyDown);
        return function cleanup() {
            document.body.removeEventListener("keydown", closeOnEscapeKeyDown);
        };
    }, []);

    const handleChange = (e) => {
        updateFormData({
            ...formData,
            [e.target.name]: e.target.value.trim()
        });
    };

    async function addProperty(formdata) {
        return fetch('http://localhost:9000/properties', {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json'
          },
          body: JSON.stringify(formdata)
        })
          .then((data) =>{ 
            console.log(data)
            return data.json()
          })
       }

    const handleSubmit = async (e) => {

        e.preventDefault()
        console.log(formData);
        const response = await addProperty(
            formData,
          );
          if (response.token) {
            console.log(response)
            console.log("Success")
          } else {
            console.log(response)
            console.log("Failed")
          }
    };

    return ReactDOM.createPortal(
        <CSSTransition
            in={props.show}
            unmountOnExit
            timeout={{ enter: 0, exit: 300 }}>
            <div style={OVERLAY_STYLE} className="modal" onClick={props.onClose}>
                <div style={MODAL_STYLES} className="modal-content" onClick={e => e.stopPropagation()}>
                    <div className="modal-header">
                        <h4 className="modal-title">{props.title}</h4>
                    </div>
                    <div className="modal-body">{props.children}
                                {/* //Main form */}
                                <div className="">
                                    <input defaultValue={props.data.title} name="title" type="text" id="form2Example1" className="form-control" onChange={handleChange} />
                                    {/* <label className="form-label" htmlFor="form2Example1">First Name</label> */}
                                    Title
                                {/* </div>
                                <div className=""> */}
                                    <input defaultValue={props.data.category.size?props.data.category[0]: " "} name="category" type="text" id="form2Example1" className="form-control" onChange={handleChange} />
                                    {/* <label className="form-label" htmlFor="form2Example1">Last Name</label> */}
                                    Category
                                </div>
                                <div className="">
                                    <input defaultValue={props.data.shortDescription} name="shortDescription" type="text" id="form2Example1" className="form-control" onChange={handleChange} />
                                    {/* <label className="form-label" htmlFor="form2Example1">Email address</label> */}
                                    Short Description
                                </div>

                                {/* Password input */}
                                <div className="">
                                    <input defaultValue={props.data.fullDescription} name="fullDescription" type="text" id="form2Example2" className="form-control" onChange={handleChange} />
                                    {/* <label className="form-label" htmlFor="form2Example2">Password</label> */}
                                    Full Description
                                </div>
                                <div className="">
                                    <input defaultValue={props.data.city} name="city" type="text" id="form2Example1" className="form-control" onChange={handleChange} />
                                    {/* <label className="form-label" htmlFor="form2Example1">Contact</label> */}
                                    City
                                </div>
                                <div className="">
                                    <input defaultValue={props.data.state} name="state" type="text" id="form2Example1" className="form-control" onChange={handleChange} />
                                    {/* <label className="form-label" htmlFor="form2Example1">Date of birth</label> */}
                                    State
                                </div>
                                <div className="">
                                    <input defaultValue={props.data.country} name="country" type="text" id="form2Example1" className="form-control" onChange={handleChange} />
                                    {/* <label className="form-label" htmlFor="form2Example1">Date of birth</label> */}
                                    Country
                                </div>
                                <div className="">
                                    <input defaultValue={props.data.hostMessage} name="hostMessage" type="text" id="form2Example1" className="form-control" onChange={handleChange} />
                                    {/* <label className="form-label" htmlFor="form2Example1">First Name</label> */}
                                    Host Message
                                </div>
                                <div className="">
                                    <input  defaultValue={parseInt(props.data.nightlyFee)} name="nightlyFee" pattern ="[0-9]"type="text" id="form2Example1" className="form-control" onChange={handleChange} />
                                    {/* <label className="form-label" htmlFor="form2Example1">Last Name</label> */}
                                    Nightly Fee
                                </div>
                                <div className="">
                                    <input defaultValue={parseInt(props.data.cleaningFee)} name="cleaningFee" pattern="[0-9]" type="text" id="form2Example1" className="form-control" onChange={handleChange} />
                                    {/* <label className="form-label" htmlFor="form2Example1">Email address</label> */}
                                    Cleaning Fee
                                </div>

                                {/* Password input */}
                                <div className="">
                                    <input defaultValue={parseInt(props.data.serviceFee)} name="serviceFee" pattern="[0-9]" type="text" id="form2Example2" className="form-control" onChange={handleChange} />
                                    {/* <label className="form-label" htmlFor="form2Example2">Password</label> */}
                                    Service Fee
                                </div>
                                <div className="">
                                    <input defaultValue={parseInt(props.data.guests)} name="guests" pattern="[0-9]" type="text" id="form2Example1" className="form-control" onChange={handleChange} />
                                    {/* <label className="form-label" htmlFor="form2Example1">Contact</label> */}
                                    Guests
                                </div>
                                <div className="">
                                    <input defaultValue={parseInt(props.data.beds)} name="beds" pattern="[0-9]" type="text" id="form2Example1" className="form-control" onChange={handleChange} />
                                    {/* <label className="form-label" htmlFor="form2Example1">Date of birth</label> */}
                                    Beds
                                </div>
                                <div className="">
                                    <input defaultValue={parseInt(props.data.baths)} name="baths" pattern="[0-9]" type="text" id="form2Example1" className="form-control" onChange={handleChange} />
                                    {/* <label className="form-label" htmlFor="form2Example1">Email address</label> */}
                                    Bathroom
                                </div>

                                {/* Password input */}
                                <div className="">
                                    <input defaultValue={props.data.houseRules.size?props.data.houseRules[0]:""} name="houseRules" type="text" id="form2Example2" className="form-control" onChange={handleChange} />
                                    {/* <label className="form-label" htmlFor="form2Example2">Password</label> */}
                                    House Rules
                                </div>
                                <div className="">
                                    <input defaultValue={props.data.healthAndSafety.size?props.data.healthAndSafety[0]:""} name="healthAndSafety" type="text" id="form2Example1" className="form-control" onChange={handleChange} />
                                    {/* <label className="form-label" htmlFor="form2Example1">Contact</label> */}
                                    Health and Safety
                                </div>
                                <div className="">
                                    <input defaultValue={props.data.cancellationPolicy.size?props.data.cancellationPolicy[0]:""} name="cancellationPolicy" type="text" id="form2Example1" className="form-control" onChange={handleChange} />
                                    {/* <label className="form-label" htmlFor="form2Example1">Date of birth</label> */}
                                    Cancellation Policy
                                </div>
                                <button type="button" className="btn" onClick={handleSubmit}>Submit</button>
                            </div>
                    </div>
                    <div className="modal-footer">
                        <button onClick={props.onClose} className="button">
                            Close
                        </button>
                    </div>
            </div>
        </CSSTransition>,
        document.getElementById("root")
    );
};

export default EditPropertyModal;
